import{c as e,i as t,n,o as r,r as i,s as a,t as o}from"./app-X_Kuuhdi.js";var s=JSON.parse(`{"path":"/products/audio-interface.html","title":"오디오 인터페이스 (Audio Interface)","lang":"ko-KR","frontmatter":{"description":"오디오 인터페이스 (Audio Interface) 오디오 인터페이스는 마이크, 기타, 신디사이저 등의 아날로그 신호를 디지털로 변환해 컴퓨터에 전달하고, 반대로 컴퓨터의 디지털 오디오를 아날로그로 변환해 스피커·헤드폰으로 출력하는 장비다. 사운드카드의 전문 외장형 버전이라고 볼 수 있다. 왜 오디오 인터페이스가 필요...","permalink":"/products/audio-interface","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"오디오 인터페이스 (Audio Interface)\\",\\"image\\":[\\"https://kmbzn.com/images/og.png\\"],\\"dateModified\\":\\"2026-06-12T15:12:24.000Z\\",\\"author\\":[]}"],["meta",{"property":"og:url","content":"https://kmbzn.com/products/audio-interface"}],["meta",{"property":"og:title","content":"오디오 인터페이스 (Audio Interface)"}],["meta",{"property":"og:description","content":"오디오 인터페이스 (Audio Interface) 오디오 인터페이스는 마이크, 기타, 신디사이저 등의 아날로그 신호를 디지털로 변환해 컴퓨터에 전달하고, 반대로 컴퓨터의 디지털 오디오를 아날로그로 변환해 스피커·헤드폰으로 출력하는 장비다. 사운드카드의 전문 외장형 버전이라고 볼 수 있다. 왜 오디오 인터페이스가 필요..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://kmbzn.com/images/og.png"}],["meta",{"property":"og:locale","content":"ko-KR"}],["meta",{"property":"og:updated_time","content":"2026-06-12T15:12:24.000Z"}],["meta",{"property":"article:modified_time","content":"2026-06-12T15:12:24.000Z"}]]},"git":{"createdTime":1781277144000,"updatedTime":1781277144000,"contributors":[{"name":"kmbzn","username":"kmbzn","email":"kmbzn24@gmail.com","commits":1,"url":"https://github.com/kmbzn"},{"name":"Claude Sonnet 4.6","username":"","email":"noreply@anthropic.com","commits":1}],"changelog":[{"hash":"867901d169b73496a8a67d2853b6d0b27bdbf876","time":1781277144000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"docs: rename all files to lowercase and add Products/Finance articles","coAuthors":[{"name":"Claude Sonnet 4.6","email":"noreply@anthropic.com"}]}]},"filePathRelative":"products/audio-interface.md","autoDesc":true}`),c={name:`audio-interface.md`},l={class:`print-section`};function u(o,s,c,u,d,f){let p=e(`DateMeta`);return a(),i(`div`,null,[n(`section`,l,[s[0]||=n(`h1`,{id:`오디오-인터페이스-audio-interface`,tabindex:`-1`},[n(`a`,{class:`header-anchor`,href:`#오디오-인터페이스-audio-interface`},[n(`span`,null,`오디오 인터페이스 (Audio Interface)`)])],-1),r(p),s[1]||=n(`p`,null,`오디오 인터페이스는 마이크, 기타, 신디사이저 등의 아날로그 신호를 디지털로 변환해 컴퓨터에 전달하고, 반대로 컴퓨터의 디지털 오디오를 아날로그로 변환해 스피커·헤드폰으로 출력하는 장비다. 사운드카드의 전문 외장형 버전이라고 볼 수 있다.`,-1)]),s[2]||=t(`<section class="print-section"><h2 id="왜-오디오-인터페이스가-필요한가" tabindex="-1"><a class="header-anchor" href="#왜-오디오-인터페이스가-필요한가"><span>왜 오디오 인터페이스가 필요한가</span></a></h2><p>컴퓨터 내장 사운드카드는 재생 품질은 충분하지만, 녹음 입력 품질이 낮고 레이턴시(지연)가 크다. 오디오 인터페이스는 다음 상황에서 필요하다.</p><table><thead><tr><th>상황</th><th>이유</th></tr></thead><tbody><tr><td>마이크 녹음</td><td>XLR 입력 + 팬텀파워(48V) 제공</td></tr><tr><td>기타·베이스 직결</td><td>고임피던스(Hi-Z) 입력 지원</td></tr><tr><td>저레이턴시 모니터링</td><td>ASIO 드라이버로 2~5ms 이하</td></tr><tr><td>스피커 출력 품질</td><td>DAC 품질이 내장보다 월등</td></tr><tr><td>멀티 채널 녹음</td><td>동시 다채널 입력 지원</td></tr></tbody></table><hr></section><section class="print-section"><h2 id="핵심-스펙-이해" tabindex="-1"><a class="header-anchor" href="#핵심-스펙-이해"><span>핵심 스펙 이해</span></a></h2></section><section class="print-section"><h3 id="입력-채널-수" tabindex="-1"><a class="header-anchor" href="#입력-채널-수"><span>입력 채널 수</span></a></h3><p>가장 먼저 결정해야 할 것. 동시에 몇 개의 소스를 녹음할지에 따라 선택이 달라진다.</p><ul><li><strong>2i2형 (2입력 2출력)</strong>: 1인 유튜버·팟캐스터, 기타+보컬 동시 녹음에 충분</li><li><strong>4i4형 이상</strong>: 밴드 녹음, 드럼 마이킹, 다채널 녹음에 필요</li></ul></section><section class="print-section"><h3 id="ad-da-변환기-품질" tabindex="-1"><a class="header-anchor" href="#ad-da-변환기-품질"><span>AD/DA 변환기 품질</span></a></h3><p>아날로그↔디지털 변환기(ADC/DAC)의 품질이 음질을 결정한다. 주요 지표:</p><ul><li><strong>다이나믹 레인지</strong>: 높을수록 좋음 (110~120dB 이상이 프로 수준)</li><li><strong>THD+N</strong>: 낮을수록 왜곡이 적음</li><li><strong>샘플링 레이트</strong>: 44.1kHz/48kHz가 기본, 96kHz/192kHz 지원 여부</li></ul></section><section class="print-section"><h3 id="마이크-프리앰프-mic-preamp" tabindex="-1"><a class="header-anchor" href="#마이크-프리앰프-mic-preamp"><span>마이크 프리앰프 (Mic Preamp)</span></a></h3><p>마이크 신호는 매우 약하기 때문에 증폭이 필요하다. 프리앰프 품질이 마이크 녹음 음질에 직접적인 영향을 미친다.</p><ul><li><strong>게인 범위</strong>: 충분한 게인(60dB 이상)이 있어야 다양한 마이크 사용 가능</li><li><strong>팬텀파워 (48V)</strong>: 콘덴서 마이크 사용 시 필수</li></ul></section><section class="print-section"><h3 id="레이턴시와-asio-드라이버" tabindex="-1"><a class="header-anchor" href="#레이턴시와-asio-드라이버"><span>레이턴시와 ASIO 드라이버</span></a></h3><p>레이턴시는 소리가 마이크에서 헤드폰으로 돌아오는 지연 시간이다.</p><ul><li>Windows: <strong>ASIO 드라이버</strong> 사용 시 5ms 이하 구현 가능 (일반 MME/WDM 드라이버는 30ms 이상)</li><li>Mac: Core Audio 기반으로 기본적으로 저레이턴시</li></ul><hr></section><section class="print-section"><h2 id="주요-제품-비교" tabindex="-1"><a class="header-anchor" href="#주요-제품-비교"><span>주요 제품 비교</span></a></h2></section><section class="print-section"><h3 id="입문-중급-10-20만원대" tabindex="-1"><a class="header-anchor" href="#입문-중급-10-20만원대"><span>입문 ~ 중급 (10~20만원대)</span></a></h3><table><thead><tr><th>제품</th><th>입출력</th><th>특징</th></tr></thead><tbody><tr><td><strong>Focusrite Scarlett Solo (4세대)</strong></td><td>1in / 2out</td><td>가장 많이 팔리는 입문기, Air 모드</td></tr><tr><td><strong>Focusrite Scarlett 2i2 (4세대)</strong></td><td>2in / 2out</td><td>입문 표준, 번들 소프트웨어 충실</td></tr><tr><td><strong>PreSonus AudioBox USB 96</strong></td><td>2in / 2out</td><td>가성비, Studio One 번들</td></tr><tr><td><strong>Behringer UMC22</strong></td><td>2in / 2out</td><td>최저가, 기본 성능</td></tr></tbody></table></section><section class="print-section"><h3 id="중급-20-40만원대" tabindex="-1"><a class="header-anchor" href="#중급-20-40만원대"><span>중급 (20~40만원대)</span></a></h3><table><thead><tr><th>제품</th><th>입출력</th><th>특징</th></tr></thead><tbody><tr><td><strong>SSL 2</strong></td><td>2in / 2out</td><td>SSL 4K 채널 스트립 기술, 측정치 우수</td></tr><tr><td><strong>SSL 2+</strong></td><td>2in / 4out</td><td>SSL 2에 모니터 믹스 출력 추가</td></tr><tr><td><strong>Audient iD4 Mk2</strong></td><td>1in / 2out</td><td>J-FET 프리앰프, 클래스A 출력</td></tr><tr><td><strong>MOTU M2</strong></td><td>2in / 2out</td><td>측정치 최상위급, 미터 디스플레이</td></tr></tbody></table></section><section class="print-section"><h3 id="측정치-최우수-30-50만원대" tabindex="-1"><a class="header-anchor" href="#측정치-최우수-30-50만원대"><span>측정치 최우수 (30~50만원대)</span></a></h3><table><thead><tr><th>제품</th><th>특징</th></tr></thead><tbody><tr><td><strong>MOTU M4</strong></td><td>4in / 4out, MOTU M2 대비 채널 확장</td></tr><tr><td><strong>Focusrite Scarlett 4i4 (4세대)</strong></td><td>4in / 4out, MIDI I/O 포함</td></tr><tr><td><strong>Universal Audio Volt 276</strong></td><td>UA 1176 리미터 탑재, 하드웨어 처리</td></tr></tbody></table><hr></section><section class="print-section"><h2 id="focusrite-scarlett-2i2-vs-ssl-2" tabindex="-1"><a class="header-anchor" href="#focusrite-scarlett-2i2-vs-ssl-2"><span>Focusrite Scarlett 2i2 vs SSL 2</span></a></h2><p>가장 많이 비교되는 두 제품.</p><table><thead><tr><th>항목</th><th>Scarlett 2i2 4세대</th><th>SSL 2</th></tr></thead><tbody><tr><td>가격</td><td>약 14만원</td><td>약 22만원</td></tr><tr><td>프리앰프</td><td>Scarlett 고유</td><td>SSL 4K 계열</td></tr><tr><td>다이나믹 레인지</td><td>~111dB</td><td>~113dB</td></tr><tr><td>Air 모드</td><td>있음 (Neve 트랜스 에뮬)</td><td>없음</td></tr><tr><td>번들 소프트웨어</td><td>Ableton Live Lite, Pro Tools 등</td><td>Ableton Live Lite</td></tr><tr><td>레거시 드라이버</td><td>있음</td><td>ASIO4ALL 필요 (Windows)</td></tr></tbody></table><p><strong>선택 기준</strong>:</p><ul><li>처음 시작하는 유튜버·팟캐스터 → <strong>Scarlett 2i2</strong>: 드라이버 안정성, 번들 충실</li><li>측정치/음질 우선 → <strong>SSL 2</strong>: 가격 대비 프리앰프 품질 우수</li><li>정밀 모니터링 중요 → <strong>MOTU M2</strong>: 최상위 측정치</li></ul><hr></section><section class="print-section"><h2 id="dac와-오디오-인터페이스의-차이" tabindex="-1"><a class="header-anchor" href="#dac와-오디오-인터페이스의-차이"><span>DAC와 오디오 인터페이스의 차이</span></a></h2><table><thead><tr><th>항목</th><th>오디오 인터페이스</th><th>DAC (독립형)</th></tr></thead><tbody><tr><td>주 용도</td><td>녹음 (입력) + 재생</td><td>재생 (출력) 전용</td></tr><tr><td>XLR 마이크 입력</td><td>있음</td><td>없음</td></tr><tr><td>팬텀파워</td><td>있음</td><td>없음</td></tr><tr><td>레이턴시 최적화</td><td>ASIO 드라이버</td><td>불필요</td></tr><tr><td>가격 (동급 기준)</td><td>더 비쌈</td><td>더 저렴</td></tr></tbody></table><p>음악 감상만이 목적이라면 오디오 인터페이스 대신 순수 DAC(헤드폰 앰프 겸용)가 합리적이다. 녹음이 필요하다면 오디오 인터페이스가 맞는 선택이다.</p><hr></section><section class="print-section"><h2 id="구매-체크리스트" tabindex="-1"><a class="header-anchor" href="#구매-체크리스트"><span>구매 체크리스트</span></a></h2><ul><li>[ ] 동시 녹음 채널 수는 몇 채널인가?</li><li>[ ] 콘덴서 마이크를 사용하는가? (팬텀파워 필수)</li><li>[ ] Windows 사용 시 제조사 ASIO 드라이버 지원 여부 확인</li><li>[ ] USB-A / USB-C 중 어떤 단자를 사용하는가?</li><li>[ ] 번들 소프트웨어가 필요한가?</li></ul><div class="hint-container tip"><p class="hint-container-title">입문자 추천</p><p>예산 15만원 이하라면 Focusrite Scarlett 2i2 4세대가 가장 안전한 선택이다. 드라이버 안정성이 검증되어 있고, 문제 발생 시 커뮤니티 자료가 풍부하다.</p></div></section>`,13)])}var d=o(c,[[`render`,u]]);export{s as _pageData,d as default};